#include <bits/stdc++.h>
using namespace std;
const int N=1e5+5;
int n,q,m,mx[N],f[N][18],dep[N];
vector<int> g[N];
void dfs(int x,int fa){
    dep[x]=dep[fa]+1;
    mx[x]=max(x,mx[fa]);
    int len=g[x].size();
    for(int i=0;i<len;i++){
        int v=g[x][i];
        f[v][0]=x;
        for(int j=1;j<18;j++)
            f[v][j]=f[f[v][j-1]][j-1];
        dfs(v,x);
    }
}
int LCA(int x,int y){
    if(dep[x]<dep[y])
        swap(x,y);
    for(int i=17;i>=0;i--)
        if(dep[f[x][i]]>=dep[y])
            x=f[x][i];
    if(x==y)
        return x;
    for(int i=17;i>=0;i--)
        if(f[x][i]!=f[y][i])
            x=f[x][i],y=f[y][i];
    return f[x][0];
}
int main(){
    scanf("%d",&n);
    for(int i=1,u;i<n;i++){
        scanf("%d",&u);
        g[u].push_back(i);
    }
    dfs(0,0);
    scanf("%d",&q);
    while(q--){
        int a,fa;
        scanf("%d",&m);
        for(int i=0;i<m;i++){
            scanf("%d",&a);
            if(!i)
                fa=a;
            else
                fa=LCA(fa,a);
        }
        printf("%d\n",mx[fa]);
    }
    return 0;
}
